# Every IAM policy is JSON with four key fields:
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",          # Allow or Deny
      "Action": "s3:GetObject",   # Which API call (avoid * always)
      "Resource": "arn:aws:s3:::my-bucket/*",  # Which resource
      "Condition": {               # Optional restrictions
        "IpAddress": {
          "aws:SourceIp": "203.0.113.0/24"
        }
      }
    }
  ]
}
